def get_required_env(name: str) -> str:
    """Get a required environment variable or raise an error."""
    value = os.environ.get(name)
    if not value:
        raise EnvironmentError(f"Required environment variable '{name}' is not set.")
    return value.strip()


def get_credential():
    """
    Get Azure credential using Managed Identity.
    
    SECURITY NOTE: Uses Managed Identity instead of connection strings or keys.
    In production, prefer UserAssigned Managed Identity with a specific client_id
    to follow least-privilege principle.
    
    For MVP, we use DefaultAzureCredential which supports:
    - Managed Identity in Azure
    - Azure CLI / VS Code credentials for local development
    """
    managed_identity_client_id = os.environ.get("AZURE_MANAGED_IDENTITY_CLIENT_ID")
    if managed_identity_client_id:
        # User-assigned managed identity (preferred for production - more explicit)
        logger.info("Using user-assigned managed identity")
        return ManagedIdentityCredential(client_id=managed_identity_client_id)
    else:
        # DefaultAzureCredential for flexibility (local dev + system-assigned MI)
        logger.info("Using DefaultAzureCredential")
        return DefaultAzureCredential()


