class BlobProcessor:
    """Processes blobs from Azure Blob Storage securely."""

    # Allowed file extensions to process (whitelist approach)
    ALLOWED_EXTENSIONS = {".json", ".csv", ".txt", ".xml"}
    # Maximum file size to process (10 MB)
    MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024

    def __init__(self, credential):
        storage_account_url = get_required_env("STORAGE_ACCOUNT_URL")
        # Validate URL format
        if not storage_account_url.startswith("https://"):
            raise ValueError("STORAGE_ACCOUNT_URL must use HTTPS")

        self.blob_service_client = BlobServiceClient(
            account_url=storage_account_url,
            credential=credential
        )
        self.container_name = get_required_env("STORAGE_CONTAINER_NAME")
        self._validate_container_name(self.container_name)

    @staticmethod
    def _validate_container_name(name: str) -> None:
        """Validate container name to prevent injection."""
        import re
        if not re.match(r'^[a-z0-9]([a-z0-9-]*[a-z0-9])?$', name):
            raise ValueError(f"Invalid container name: {name}")
        if len(name) < 3 or len(name) > 63:
            raise ValueError(f"Container name must be 3-63 characters: {name}")

    @staticmethod
    def _validate_blob_name(name: str) -> None:
        """Validate blob name to prevent path traversal attacks."""
        if not name:
            raise ValueError("Blob name cannot be empty")
        # Prevent path traversal
        normalized = os.path.normpath(name)
        if normalized.startswith("..") or "/../" in name or name.startswith("/"):
            raise ValueError(f"Invalid blob name (potential path traversal): {name}")
        # Check extension whitelist
        _, ext = os.path.splitext(name.lower())
        if ext not in BlobProcessor.ALLOWED_EXTENSIONS:
            raise ValueError(
                f"File extension '{ext}' not allowed. "
                f"Allowed: {BlobProcessor.ALLOWED_EXTENSIONS}"
            )

    def read_blob(self, blob_name: str) -> dict[str, Any]:
        """Read and validate a blob from storage."""
        self._validate_blob_name(blob_name)

        container_client = self.blob_service_client.get_container_client(
            self.container_name
        )
        blob_client = container_client.get_blob_client(blob_name)

        # Check blob properties before downloading
        properties = blob_client.get_blob_properties()
        blob_size = properties.size

        if blob_size > self.MAX_FILE_SIZE_BYTES:
            raise ValueError(
                f"Blob '{blob_name}' size ({blob_size} bytes) exceeds "
                f"maximum allowed size ({self.MAX_FILE_SIZE_BYTES} bytes)"
            )

        logger.info(
            "Downloading blob: %s (size: %d bytes)",
            blob_name, blob_size
        )

        # Download blob content
        blob_data = blob_client.download_blob().readall()

        # Compute checksum for integrity verification
        content_hash = hashlib.sha256(blob_data).hexdigest()

        return {
            "blob_name": blob_name,
            "content": blob_data,
            "size": blob_size,
            "content_hash": content_hash,
            "content_type": properties.content_settings.content_type,
            "last_modified": properties.last_modified.isoformat()
                if properties.last_modified else None,
        }

    def process_blob_content(self, blob_data: dict[str, Any]) -> dict[str, Any]:
        """Process blob content and return structured results."""
        blob_name = blob_data["blob_name"]
        content = blob_data["content"]
        _, ext = os.path.splitext(blob_name.lower())

        result = {
            "source_blob": blob_name,
            "source_hash": blob_data["content_hash"],
            "source_size": blob_data["size"],
            "processed_at": datetime.now(timezone.utc).isoformat(),
            "status": "processed",
        }

        try:
            if ext == ".json":
                # Parse JSON with size limit already enforced
                parsed = json.loads(content.decode("utf-8"))
                result["record_count"] = (
                    len(parsed) if isinstance(parsed, list) else 1
                )
                result["data_summary"] = self._summarize_json(parsed)
            elif ext == ".csv":
                lines = content.decode("utf-8").strip().split("\n")
                result["record_count"] = max(0, len(lines) - 1)  # Exclude header
                result["headers"] = lines[0] if lines else ""
            elif ext == ".txt":
                text = content.decode("utf-8")
                result["record_count"] = len(text.split("\n"))
                result["character_count"] = len(text)
            elif ext == ".xml":
                # Basic XML processing - in production use defusedxml
                text = content.decode("utf-8")
                result["record_count"] = text.count("<")
                result["character_count"] = len(text)
            else:
                result["status"] = "unsupported_format"

        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            logger.warning("Error processing blob %s: %s", blob_name, str(e))
            result["status"] = "error"
            result["error_message"] = f"Content parsing error: {type(e).__name__}"

        return result

    @staticmethod
    def _summarize_json(data: Any) -> dict[str, Any]:
        """Create a safe summary of JSON data without exposing sensitive content."""
        if isinstance(data, list):
            return {
                "type": "array",
                "length": len(data),
                "item_type": type(data[0]).__name__ if data else "empty",
            }
        elif isinstance(data, dict):
            return {
                "type": "object",
                "key_count": len(data),
                "keys": list(data.keys())[:20],  # Limit exposed keys
            }
        else:
            return {"type": type(data).__name__}


class CosmosDBWriter:
    """Writes processing results to Cosmos DB securely."""

    def __init__(self, credential):
        cosmos_endpoint = get_required_env("COSMOS_DB_ENDPOINT")
        if not cosmos_endpoint.startswith("https://"):
            raise ValueError("COSMOS_DB_ENDPOINT must use HTTPS")

        self.client = CosmosClient(
            url=cosmos_endpoint,
            credential=credential
        )
        self.database_name = get_required_env("COSMOS_DB_DATABASE")
        self.container_name = get_required_env("COSMOS_DB_CONTAINER")
        self._container = None

    def _get_container(self):
        """Get or create the Cosmos DB container (lazy initialization)."""
        if self._container is None:
            database = self.client.get_database_client(self.database_name)
            self._container = database.get_container_client(self.container_name)
        return self._container

    def write_result(self, result: dict[str, Any]) -> dict[str, Any]:
        """Write a processing result to Cosmos DB."""
        container = self._get_container()

        # Generate a deterministic ID based on source blob and processing time
        doc_id = hashlib.sha256(
            f"{result['source_blob']}:{result['processed_at']}".encode()
        ).hexdigest()[:32]

        document = {
            "id": doc_id,
            "partitionKey": self._get_partition_key(result),
            **result,
            "created_at": datetime.now(timezone.utc).isoformat(),
            "schema_version": "1.0",
        }

        # Sanitize document - remove any binary content
        document = self._sanitize_document(document)

        logger.info(
            "Writing document to Cosmos DB: id=%s, partition=%s",
            doc_id, document["partitionKey"]
        )

        response = container.upsert_item(body=document)
        return {
            "id": response["id"],
            "partition_key": response["partitionKey"],
            "status": "written",
        }

    @staticmethod
    def _get_partition_key(result: dict[str, Any]) -> str:
        """Generate partition key from the processing date."""
        processed_at = result.get("processed_at", datetime.now(timezone.utc).isoformat())
        # Use date as partition key for time-based queries
        return processed_at[:10]  # YYYY-MM-DD

    @staticmethod
    def _sanitize_document(doc: dict[str, Any]) -> dict[str, Any]:
        """Remove non-serializable or sensitive fields from document."""
        sanitized = {}
        sensitive_keys = {"password", "secret", "token", "key", "credential"}

        for k, v in doc.items():
            # Skip sensitive fields
            if k.lower() in sensitive_keys:
                continue
            # Skip binary content
            if isinstance(v, (bytes, bytearray)):
                continue
            # Recursively sanitize nested dicts
            if isinstance(v, dict):
                sanitized[k] = CosmosDBWriter._sanitize_document(v)
            else:
                sanitized[k] = v

        return sanitized


class EventGridNotifier:
    """Sends notifications via Event Grid securely."""

    def __init__(self, credential):
        topic_endpoint = get_required_env("EVENT_GRID_TOPIC_ENDPOINT")
        if not topic_endpoint.startswith("https://"):
            raise ValueError("EVENT_GRID_TOPIC_ENDPOINT must use HTTPS")

        self.client = EventGridPublisherClient(
            endpoint=topic_endpoint,
            credential=credential
        )
        self.source = get_required_env("EVENT_GRID_EVENT_SOURCE")

    def send_notification(
        self,
        event_type: str,
        subject: str,
        data: dict[str, Any]
    ) -> None:
        """Send a CloudEvent notification."""
        # Sanitize event data - don't include raw content or sensitive info
        safe_data = self._sanitize_event_data(data)

        event = CloudEvent(
            source=self.source,
            type=event_type,
            subject=subject,
            data=safe_data,
            time=datetime.now(timezone.utc),
        )

        logger.info(
            "Sending Event Grid notification: type=%s, subject=%s",
            event_type, subject
        )

        self.client.send(event)

    @staticmethod
    def _sanitize_event_data(data: dict[str, Any]) -> dict[str, Any]:
        """Remove sensitive or large data from event payload."""
        # Only include safe, summary-level fields in events
        allowed_fields = {
            "source_blob", "source_hash", "source_size", "processed_at",
            "status", "record_count", "error_message", "id",
            "partition_key", "schema_version",
        }
        return {k: v for k, v in data.items() if k in allowed_fields}


