@app.blob_trigger(
    arg_name="myblob",
    path="{STORAGE_CONTAINER_NAME}/{name}",
    connection="STORAGE_CONNECTION__serviceUri"  # Uses identity-based connection
)
def process_blob_trigger(myblob: func.InputStream):
    """
    Azure Function triggered by new blobs in storage.
    
    Uses Managed Identity for all Azure service authentication.
    No secrets or connection strings in code or configuration.
    
    Identity-based blob trigger connection requires:
    - App setting: STORAGE_CONNECTION__serviceUri = https://<account>.blob.core.windows.net
    - Role: Storage Blob Data Owner on the storage account (for trigger infrastructure)
    """
    blob_name = myblob.name
    logger.info("Blob trigger fired for: %s", blob_name)

    try:
        # Initialize credential once and share across services
        credential = get_credential()

        # Extract just the blob name (remove container prefix if present)
        container_name = os.environ.get("STORAGE_CONTAINER_NAME", "")
        if blob_name.startswith(f"{container_name}/"):
            clean_blob_name = blob_name[len(container_name) + 1:]
        else:
            clean_blob_name = blob_name

        # Step 1: Process the blob
        processor = BlobProcessor(credential)
        blob_data = processor.read_blob(clean_blob_name)
        result = processor.process_blob_content(blob_data)

        logger.info(
            "Blob processed: %s, status=%s, records=%s",
            clean_blob_name,
            result.get("status"),
            result.get("record_count", "N/A")
        )

        # Step 2: Write results to Cosmos DB
        cosmos_writer = CosmosDBWriter(credential)
        write_response = cosmos_writer.write_result(result)

        logger.info(
            "Result written to Cosmos DB: id=%s",
            write_response.get("id")
        )

        # Step 3: Send notification via Event Grid
        notifier = EventGridNotifier(credential)

        event_type = (
            "BlobProcessing.Completed"
            if result["status"] == "processed"
            else "BlobProcessing.Failed"
        )

        notification_data = {**result, **write_response}
        notifier.send_notification(
            event_type=event_type,
            subject=f"/blobs/{clean_blob_name}",
            data=notification_data,
        )

        logger.info(
            "Processing complete for blob: %s (event: %s)",
            clean_blob_name, event_type
        )

    except ValueError as e:
        logger.error("Validation error processing blob %s: %s", blob_name, str(e))
        _send_error_notification(blob_name, "ValidationError", str(e))
    except EnvironmentError as e:
        logger.error("Configuration error: %s", str(e))
        raise  # Re-raise config errors - function cannot operate
    except Exception as e:
        logger.exception("Unexpected error processing blob %s: %s", blob_name, str(e))
        _send_error_notification(blob_name, "UnexpectedError", str(e))
        raise  # Re-raise to trigger retry policy


@app.route(route="process", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def process_blob_http(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP-triggered function to manually process a specific blob.
    
    Requires Function-level auth key for access control.
    
    Request body: {"blob_name": "path/to/file.json"}
    """
    logger.info("HTTP trigger: process blob request")

    try:
        req_body = req.get_json()
    except ValueError:
        return func.HttpResponse(
            json.dumps({"error": "Invalid JSON in request body"}),
            status_code=400,
            mimetype="application/json"
        )

    blob_name = req_body.get("blob_name")
    if not blob_name or not isinstance(blob_name, str):
        return func.HttpResponse(
            json.dumps({"error": "Missing or invalid 'blob_name' in request body"}),
            status_code=400,
            mimetype="application/json"
        )

    try:
        credential = get_credential()

        # Process
        processor = BlobProcessor(credential)
        blob_data = processor.read_blob(blob_name)
        result = processor.process_blob_content(blob_data)

        # Write to Cosmos DB
        cosmos_writer = CosmosDBWriter(credential)
        write_response = cosmos_writer.write_result(result)

        # Notify
        notifier = EventGridNotifier(credential)
        event_type = (
            "BlobProcessing.Completed"
            if result["status"] == "processed"
            else "BlobProcessing.Failed"
        )
        notifier.send_notification(
            event_type=event_type,
            subject=f"/blobs/{blob_name}",
            data={**result, **write_response},
        )

        response_data = {
            "status": "success",
            "blob_name": blob_name,
            "processing_status": result["status"],
            "cosmos_db_id": write_response.get("id"),
            "record_count": result.get("record_count"),
        }

        return func.HttpResponse(
            json.dumps(response_data),
            status_code=200,
            mimetype="application/json"
        )

    except ValueError as e:
        logger.warning("Validation error: %s", str(e))
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            status_code=400,
            mimetype="application/json"
        )
    except Exception as e:
        logger.exception("Error processing blob %s: %s", blob_name, str(e))
        return func.HttpResponse(
            json.dumps({"error": "Internal processing error"}),
            status_code=500,
            mimetype="application/json"
        )


@app.route(route="health", methods=["GET"], auth_level=func.AuthLevel.ANONYMOUS)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint - verifies service connectivity."""
    health = {
        "status": "healthy",
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "checks": {}
    }

    try:
        credential = get_credential()

        # Check Storage connectivity
        try:
            storage_url = get_required_env("STORAGE_ACCOUNT_URL")
            blob_client = BlobServiceClient(
                account_url=storage_url, credential=credential
            )
            blob_client.get_account_information()
            health["checks"]["storage"] = "connected"
        except Exception as e:
            health["checks"]["storage"] = f"error: {type(e).__name__}"
            health["status"] = "degraded"

        # Check Cosmos DB connectivity
        try:
            cosmos_endpoint = get_required_env("COSMOS_DB_ENDPOINT")
            cosmos_client = CosmosClient(
                url=cosmos_endpoint, credential=credential
            )
            # List databases to verify connectivity
            list(cosmos_client.list_databases())
            health["checks"]["cosmos_db"] = "connected"
        except Exception as e:
            health["checks"]["cosmos_db"] = f"error: {type(e).__name__}"
            health["status"] = "degraded"

        # Check required environment variables
        required_vars = [
            "STORAGE_ACCOUNT_URL", "STORAGE_CONTAINER_NAME",
            "COSMOS_DB_ENDPOINT", "COSMOS_DB_DATABASE", "COSMOS_DB_CONTAINER",
            "EVENT_GRID_TOPIC_ENDPOINT", "EVENT_GRID_EVENT_SOURCE",
        ]
        missing_vars = [v for v in required_vars if not os.environ.get(v)]
        if missing_vars:
            health["checks"]["configuration"] = f"missing: {missing_vars}"
            health["status"] = "degraded"
        else:
            health["checks"]["configuration"] = "complete"

    except Exception as e:
        health["status"] = "unhealthy"
        health["checks"]["credential"] = f"error: {type(e).__name__}"

    status_code = 200 if health["status"] == "healthy" else 503
    return func.HttpResponse(
        json.dumps(health),
        status_code=status_code,
        mimetype="application/json"
    )


def _send_error_notification(blob_name: str, error_type: str, error_message: str):
    """Attempt to send an error notification via Event Grid."""
    try:
        credential = get_credential()
        notifier = EventGridNotifier(credential)
        notifier.send_notification(
            event_type="BlobProcessing.Error",
            subject=f"/blobs/{blob_name}",
            data={
                "source_blob": blob_name,
                "status": "error",
                "error_message": f"{error_type}: {error_message}",
                "processed_at": datetime.now(timezone.utc).isoformat(),
            },
        )
    except Exception as e:
        logger.error(
            "Failed to send error notification for %s: %s",
            blob_name, str(e)
        )